-- ---- STUDENT 1: Anne Wanjiku | Computer Science | Safaricom PLC ----
INSERT INTO logbook (AttachmentID, WeekNumber, StartDate, EndDate, Activities, Status, IssueDate, AcademicSupervisorComments, HostSupervisorComments, SubmittedAt) VALUES
(1,1,'2026-02-02','2026-02-06','{"monday":{"task":"Orientation to Safaricom ICT Division and introduction to the DevOps team","comment":"Keen and enthusiastic on first day"},"tuesday":{"task":"Reviewed Safaricom internal developer tools documentation and CI/CD pipelines","comment":"Quick grasp of internal systems"},"wednesday":{"task":"Set up development environment with Docker, Git and internal SDKs","comment":"Setup completed independently"},"thursday":{"task":"Attended sprint planning meeting and assigned to the API integration team","comment":"Good understanding of agile methodology"},"friday":{"task":"Submitted first logbook and self-assessment","comment":"Detailed and reflective submission"}}','Approved','2026-02-02','Anne demonstrates excellent technical aptitude and is integrating well into the Safaricom DevOps environment.','Anne had a remarkable first week. She required minimal hand-holding and contributed meaningfully from day one.','2026-02-06 17:00:00'),
(1,2,'2026-02-09','2026-02-13','{"monday":{"task":"Worked on REST API endpoints for M-Pesa Daraja B2C integration","comment":"Solid API understanding demonstrated"},"tuesday":{"task":"Participated in code review session and identified a null pointer exception bug","comment":"Good debugging instincts"},"wednesday":{"task":"Wrote unit tests for the B2C payment module using JUnit","comment":"Test coverage improved significantly"},"thursday":{"task":"Collaborated with backend team to deploy API to staging environment","comment":"Seamless deployment collaboration"},"friday":{"task":"Documented API endpoints using Postman and shared with team","comment":"Clear and developer-friendly documentation"}}','Approved','2026-02-09','Anne''s work on the M-Pesa Daraja API is technically sound and production-ready. Excellent week.','Her API documentation is the best we have seen from an intern. The backend team is impressed.','2026-02-13 17:00:00'),
(1,3,'2026-02-16','2026-02-20','{"monday":{"task":"Implemented OAuth 2.0 authentication for the internal developer portal","comment":"Correct and secure OAuth implementation"},"tuesday":{"task":"Attended a workshop on Safaricom cloud infrastructure using Google Cloud Platform","comment":"Engaged with great questions on GCP"},"wednesday":{"task":"Assisted in migrating a legacy microservice to containerized Docker format","comment":"Good understanding of containerization concepts"},"thursday":{"task":"Participated in a knowledge sharing session on API security best practices","comment":"Shared key insights with the team"},"friday":{"task":"Submitted weekly logbook and prepared technical reflection note","comment":"Technical reflection shows excellent growth"}}','Approved','2026-02-16','Anne''s OAuth implementation is already in code review for production. Outstanding technical work.','Her cloud workshop contributions showed deep understanding. The cloud team has requested her for a mini-project.','2026-02-20 17:00:00'),
(1,4,'2026-02-23','2026-02-27','{"monday":{"task":"Developed a real-time data streaming pipeline using Apache Kafka","comment":"Advanced data engineering skills demonstrated"},"tuesday":{"task":"Integrated the Kafka pipeline with the analytics dashboard","comment":"Integration tested and fully functional"},"wednesday":{"task":"Optimized database query performance reducing load by 35% in the reporting module","comment":"Significant performance improvement"},"thursday":{"task":"Presented the Kafka pipeline architecture to the engineering team","comment":"Clear and technically sound presentation"},"friday":{"task":"Submitted logbook and monthly self-evaluation report","comment":"Comprehensive and honest self-assessment"}}','Approved','2026-02-23','Kafka pipeline development at this level is exceptional for a student attachment. Anne is truly gifted.','The Kafka pipeline she built is being considered for production deployment. We are very impressed.','2026-02-27 17:00:00'),
(1,5,'2026-03-02','2026-03-06','{"monday":{"task":"Worked on the Safaricom customer data analytics module using Python and Pandas","comment":"Strong data analytics skills shown"},"tuesday":{"task":"Built machine learning model for customer churn prediction using scikit-learn","comment":"ML model achieves 87% accuracy - impressive"},"wednesday":{"task":"Integrated the churn model with the CRM dashboard via REST API","comment":"Seamless integration achieved"},"thursday":{"task":"Prepared a technical presentation on ML model results for the data science team","comment":"Presentation was highly praised"},"friday":{"task":"Submitted logbook and documented ML model for handover","comment":"Model documentation is thorough"}}','Approved','2026-03-02','Anne''s ML churn prediction model is of publishable quality. She is a standout student.','The data science team has incorporated her model into the CRM roadmap. Exceptional contribution.','2026-03-06 17:00:00'),
