INSERT INTO assessment (AttachmentID, AssessmentDate, AssessmentType, Marks, Remarks, CriteriaScores, LecturerID, SupervisionComments, Status) VALUES
-- AttachmentID 1: Anne Wanjiku @ Safaricom
(1, '2026-03-01', 'First Assessment', 82.00, 'Anne demonstrates exceptional technical skills in software development. Her M-Pesa API work is production-ready and her ML model shows advanced capability beyond her year of study.', '["9","8","8","8","9","8","8","8","8","8"]', 2, 'This is the most technically capable student I have supervised in 8 years. Anne is a natural software engineer.', 'Completed'),
(1, '2026-04-10', 'Final Assessment', 89.00, 'Anne has completed an extraordinary attachment with contributions to production systems, a hackathon win, and a CI/CD pipeline that is now in use across the DevOps team. A genuinely exceptional student.', '["9","9","9","9","9","8","9","9","9","9"]', 2, 'Anne''s growth from first to final assessment is remarkable. Her final performance is equivalent to a mid-level software engineer. Distinguished achievement.', 'Completed'),
-- AttachmentID 2: Kevin Omondi @ KCB
(2, '2026-03-01', 'First Assessment', 80.00, 'Kevin demonstrates strong financial accounting skills. His IFRS 9 loan impairment work and bank reconciliation accuracy are impressive. Shows good commercial awareness and professional conduct.', '["8","8","8","8","8","9","8","8","8","7"]', 3, 'Kevin is performing at a level significantly above his peer group. His IFRS 9 application is technically correct which is rare among undergraduates.', 'Completed'),
(2, '2026-04-10', 'Final Assessment', 87.00, 'Kevin has made extraordinary contributions to KCB including a VBA reconciliation tool deployed to all regional offices and representing KCB at the Kenya Bankers Association forum. His final report is of research quality.', '["9","9","8","9","9","8","8","9","9","8"]', 3, 'Kevin''s final performance exceeds my expectations. His research quality is at postgraduate level. Ready for the professional accounting world.', 'Completed'),
-- AttachmentID 3: Faith Jepchirchir @ KEMRI
(3, '2026-03-01', 'First Assessment', 85.00, 'Faith demonstrates world-class actuarial and health economics skills. Her Markov model, R Shiny disease burden model and WHO workshop representation are extraordinary achievements for an attachment student.', '["9","9","8","8","9","8","9","9","8","8"]', 4, 'Faith is the most talented actuarial science student I have supervised. Her technical depth is at MSc level. The KEMRI Outstanding Intern Award is thoroughly deserved.', 'Completed'),
(3, '2026-04-10', 'Final Assessment', 90.00, 'Faith has achieved the pinnacle of attachment performance. Journal article submitted for peer review, national television appearance, WHO workshop representation, and KEMRI Outstanding Intern Award. A once-in-a-decade student.', '["9","9","9","9","9","9","9","9","9","9"]', 4, 'Full marks on all criteria is unprecedented in my career as a supervisor. Faith''s attachment performance is a benchmark for all future students. She has shown what is truly possible.', 'Completed'),
-- AttachmentID 4: Joseph Mutua @ Nairobi City County
(4, '2026-03-01', 'First Assessment', 78.00, 'Joseph demonstrates strong journalism and communications skills. His press releases, social media management and video documentary production show professional quality output. Good ethical conduct throughout.', '["8","8","7","8","8","8","7","8","8","8"]', 5, 'Joseph''s journalism work is of broadcast industry standard. His social media analytics and documentary production capabilities are impressive for a student.', 'Completed'),
(4, '2026-04-10', 'Final Assessment', 84.00, 'Joseph has had an outstanding attachment - coordinating a Governor''s press briefing, creating a county-adopted crisis protocol, producing a nationally read investigative series and representing the county at a national conference. A remarkable communications professional.', '["9","8","8","8","9","8","8","9","8","9"]', 5, 'Joseph''s final performance is exceptional. He demonstrates the journalism competencies of a seasoned professional. A future media leader for Kenya.', 'Completed'),
-- AttachmentID 5: Brenda Chepkemoi @ KRA
(5, '2026-03-01', 'First Assessment', 83.00, 'Brenda demonstrates exceptional software engineering capabilities. Her KRA iTax API development, ML anomaly detection system and security contributions show extraordinary technical depth.', '["9","8","8","9","8","8","9","8","9","8"]', 6, 'Brenda is the most technically capable software engineering student I have supervised. Her ML fraud detection system is in KRA production -- a student''s work protecting government revenue.', 'Completed'),
(5, '2026-04-10', 'Final Assessment', 90.00, 'Brenda developed an ML fraud detection system now in KRA production, won the KRA Innovator of the Year Award (first intern in history), and presented at the Africa Tax Technology Conference. The highest achievable distinction.', '["9","9","9","9","9","9","9","9","9","9"]', 6, 'Brenda''s attachment output is beyond any student I have ever supervised. She is already a professional software engineer contributing to Kenya''s government digital transformation. Absolutely outstanding.', 'Completed'),
-- AttachmentID 6: George Mwangi @ Equity Bank
(6, '2026-03-01', 'First Assessment', 75.00, 'George demonstrates solid IT fundamentals with strong network administration and security skills. His automation script and security vulnerability identification show good practical competency.', '["7","8","7","8","7","8","8","7","8","7"]', 7, 'George is a reliable and capable IT student. His security finding at Equity Bank prevented a potentially critical data breach. Good professional conduct throughout.', 'Completed'),
(6, '2026-04-10', 'Final Assessment', 82.00, 'George built an MDM system now deployed across Equity agent banking network, represented Equity at an Africa technology conference and developed an automation tool saving the IT team 2 hours daily. Impressive attachment contributions.', '["8","8","8","8","8","9","8","8","8","9"]', 7, 'George has grown significantly from first to final assessment. His MDM deployment and conference representation show professional maturity. An impressive IT professional in the making.', 'Completed'),
-- AttachmentID 7: Sheila Achieng @ Kenya Power
(7, '2026-03-01', 'First Assessment', 79.00, 'Sheila demonstrates excellent HR management skills. Her retention analysis recommendations were formally adopted by Kenya Power, and her talent management capabilities are impressive for a student.', '["8","8","7","8","8","8","8","8","7","8"]', 8, 'Sheila is a natural HR professional. Her organizational development recommendations at Kenya Power show strategic thinking beyond her years. Excellent student.', 'Completed'),
(7, '2026-04-10', 'Final Assessment', 85.00, 'Sheila organized a wellness event for 200+ staff, developed a performance appraisal framework rolled out to 2,000 technicians, led a graduate trainee recruitment and designed an onboarding programme now in use by Kenya Power. Exceptional HRM contributions.', '["9","8","8","9","9","8","8","9","8","9"]', 8, 'Sheila''s final attachment performance is at the level of a seasoned HR business partner. Her organizational contributions to Kenya Power are significant and lasting.', 'Completed'),
-- AttachmentID 8: Isaac Kiptoo @ Nation Media
(8, '2026-03-01', 'First Assessment', 76.00, 'Isaac demonstrates strong management accounting and financial analysis skills. His revenue forecasting model and NMG consolidated accounts contributions are of professional standard.', '["8","7","8","7","7","8","8","7","8","8"]', 9, 'Isaac is a solid accounting student with strong financial modeling skills. His KPMG audit response quality surprised even the audit partners. Good progress.', 'Completed'),
(8, '2026-04-10', 'Final Assessment', 83.00, 'Isaac built a Power BI dashboard deployed to all 15 NMG finance managers, developed a revenue forecasting model used in FY2027 planning and independently led management accounts preparation. Extraordinary accounting achievements.', '["8","9","8","8","8","8","8","9","8","9"]', 9, 'Isaac''s final achievement of independently leading management accounts preparation is exceptional for a student. His Power BI tool deployment shows he impacts operations beyond his individual work. Excellent outcome.', 'Completed'),
-- AttachmentID 9: Vivian Moraa @ Kenya Airways
(9, '2026-03-01', 'First Assessment', 81.00, 'Vivian demonstrates exceptional public relations and communications skills. Her Brand Ambassador Programme that received VP approval, crisis communications management and published PR article show remarkable professional competency.', '["8","8","8","9","8","8","9","8","8","8"]', 10, 'Vivian is the most creative and strategically minded communications student I have supervised. Her crisis management capabilities are already at industry professional level. Excellent.', 'Completed'),
(9, '2026-04-10', 'Final Assessment', 88.00, 'Vivian won the Kenya PR Society Best PR Campaign Award for the Brand Ambassador Programme she created for KQ, managed a major communications crisis reducing negative sentiment by 60%, and raised KQ''s CSR index by 18 points. A truly extraordinary PR student.', '["9","9","9","8","9","9","8","9","9","9"]', 10, 'Vivian''s final performance is that of an experienced PR director. Her award win, crisis management and CSR strategy demonstrate multi-dimensional PR excellence. A future PR titan for Kenya.', 'Completed'),
-- AttachmentID 10: Dennis Kipchoge @ SIB
(10, '2026-03-01', 'First Assessment', 80.00, 'Dennis demonstrates strong investment analysis and financial modeling skills. His DCF valuation, equity research and Treasury bond pricing model show solid capital markets understanding.', '["8","8","8","8","8","8","8","8","8","8"]', 11, 'Dennis is a strong finance student with excellent quantitative skills. His REIT prospectus sections and yield curve analysis demonstrate knowledge beyond the typical undergraduate level.', 'Completed'),
(10, '2026-04-10', 'Final Assessment', 87.00, 'Dennis built a Python portfolio attribution tool used by all SIB asset managers, attended a SIB Board meeting as research analyst (first intern in SIB history), and delivered M&A analysis rated Exceptional by the Managing Director. Extraordinary capital markets achievement.', '["9","9","8","9","8","9","9","8","9","9"]', 11, 'Dennis has demonstrated investment banking capabilities at the level of a second-year analyst. His Board meeting attendance and MD-endorsed M&A analysis are unprecedented for a student. A future capital markets leader.', 'Completed'),
-- AttachmentID 11: Sharon Njeri @ KNBS
(11, '2026-03-01', 'First Assessment', 77.00, 'Sharon demonstrates strong statistical and research skills. Her pharmaceutical CPI analysis incorporated in the official KNBS monthly report and her national television presentation on KBC show exceptional capability.', '["8","7","8","8","7","8","8","8","8","7"]', 12, 'Sharon is a disciplined and capable pharmaceutical sciences student applying statistical methods innovatively. Her work at KNBS is generating national-level outputs which is extraordinary.', 'Completed'),
(11, '2026-04-10', 'Final Assessment', 84.00, 'Sharon published an official KNBS statistical brief, developed a Tableau dashboard adopted as the standard pharmaceutical sector visualization tool, and presented as a top-rated speaker at the East African Agricultural law symposium. A remarkable Health Sciences student.', '["8","8","8","9","8","8","8","9","8","9"]', 12, 'Sharon''s final performance confirms her as a top statistical researcher. Her combination of technical skills, communication ability and research output is exceptional. Ready for a career in national statistics.', 'Completed'),
-- AttachmentID 12: Peter Karanja @ Co-op Bank
(12, '2026-03-01', 'First Assessment', 74.00, 'Peter demonstrates good agricultural finance understanding. His tea cooperative field visit report, maize cooperative credit assessment and agri-lending portfolio analysis show solid practical capability.', '["7","8","7","7","8","7","8","7","7","8"]', 13, 'Peter brings a unique combination of agricultural science and banking knowledge to his attachment. His ML agri-credit scoring model shows creative thinking. Good progress in week one.', 'Completed'),
(12, '2026-04-10', 'Final Assessment', 81.00, 'Peter identified KES 50M in new agri-lending opportunities, developed a financial literacy curriculum now being rolled out to 50 cooperatives, built an ML credit model piloted by Co-op Bank, and developed the FY2026/27 Agri-Finance product roadmap. Extraordinary agricultural finance achievement.', '["8","8","8","8","8","8","9","8","8","9"]', 13, 'Peter''s combination of agricultural knowledge and financial modeling capability is exceptional. His attachment contributions will benefit thousands of Kenyan smallholder farmers. A future agricultural finance leader.', 'Completed'),
-- AttachmentID 13: Miriam Wasike @ KALRO (Ongoing - First Assessment only ready)
(13, '2026-03-01', 'First Assessment', 83.00, 'Miriam demonstrates exceptional legal skills. Her seed licensing agreement, CIMMYT international negotiations, KALRO Board Legal Sub-committee presentation and USAID grant legal framework show extraordinary legal capability for an LLB student.', '["8","9","8","8","9","8","9","8","8","8"]', 14, 'Miriam is the most legally capable student I have supervised in 12 years at the law faculty. Her international agricultural law experience is remarkable. She is ready for a career at the top tier of the profession.', 'Completed'),
(13, '2026-04-10', 'Final Assessment', 88.00, 'Miriam finalized the KALRO-USAID grant agreement, drafted board-approved GMO compliance resolutions, was rated top presenter at the East African Agricultural Law Symposium and trained 120 KALRO staff on legal compliance. An outstanding law student.', '["9","9","8","9","9","8","9","8","9","9"]', 14, 'Miriam''s intellectual breadth, legal technical skill and professional conduct are at the level of a qualified advocate. Her work at KALRO will have lasting national impact. A future legal luminary.', 'Completed'),
-- AttachmentID 14: David Otieno @ EABL (Ongoing - Both assessments done)
(14, '2026-03-01', 'First Assessment', 78.00, 'David demonstrates strong multimedia journalism skills. His Business Daily article publication, viral documentary and EABL communications management show professional broadcast industry capability.', '["8","7","8","8","8","7","8","8","8","8"]', 15, 'David is an exceptionally talented multimedia journalist. His ability to produce broadcast-standard content while managing major corporate communications operations is remarkable.', 'Completed'),
(14, '2026-04-10', 'Final Assessment', 85.00, 'David launched EABL''s first podcast (5,000 listens in week one), won the Kenya Film Commission Media Innovation Award (first intern in EABL history), produced content with national parliamentary reference and developed a digital strategy driving 30% increase in EABL''s digital reach.', '["9","8","8","9","9","8","8","9","8","9"]', 15, 'David''s achievement of winning an industry award while on student attachment is unprecedented. His final performance confirms him as one of the most talented journalism students this department has produced.', 'Completed'),
-- AttachmentID 15: Emily Chemutai @ KNH (Ongoing - First Assessment done, Final pending completion)
(15, '2026-03-01', 'First Assessment', 76.00, 'Emily demonstrates strong healthcare finance skills. Her NHIF reconciliation, donor compliance reports, dialysis department CBA and revenue forecasting model show impressive capability in the complex healthcare finance environment.', '["8","7","8","7","8","8","7","8","8","7"]', 16, 'Emily is performing well in the challenging healthcare finance environment. Her dialysis CBA contributing to KNH Board discussion is remarkable. Good progress at this stage.', 'Completed'),
(15, '2026-04-10', 'Final Assessment', 82.00, 'Emily developed a revenue model adopted by KNH CFO for the annual budget, had 2 of her policy recommendations adopted by the KNH Board, built an asset lifecycle costing model saving KES 5M and represented KNH at a National Treasury seminar. An outstanding healthcare finance student.', '["8","8","8","8","8","8","9","8","8","9"]', 16, 'Emily''s final performance reflects a student capable of operating in a complex multi-stakeholder environment. Her KNH Board impact at student level is extraordinary. Some clearances still outstanding but her academic work is complete.', 'Completed');

