-- SECTION 10: ATTACHMENT OPPORTUNITIES (10 Job Listings from host organizations)
-- =============================================================================
INSERT INTO attachmentopportunity (OpportunityID, HostOrgID, Description, EligibilityCriteria, ApplicationStartDate, ApplicationEndDate, Status) VALUES
(1,  1,  'Software Engineer Intern - Join Safaricom''s award-winning technology team. Work on real products that serve 40M+ Kenyans. Exposure to M-Pesa, Cloud, AI and DevOps practices in a dynamic agile environment.', 'BSc Computer Science, Software Engineering or related field. Minimum CGPA: 3.0. Basic programming knowledge in Python, Java or JavaScript required.', '2025-10-01', '2025-11-30', 'Closed'),
(2,  2,  'Banking Operations Intern - KCB Group offers a comprehensive banking internship covering corporate banking, retail operations, treasury and trade finance. Gain practical experience in Kenya''s leading banking group.', 'BCom Finance, Accounting or Banking. Minimum CGPA: 2.8. Proficiency in Excel required. Good analytical and communication skills.', '2025-10-01', '2025-11-30', 'Closed'),
(3,  3,  'Health Research Data Analyst Intern - KEMRI offers positions for students to participate in cutting-edge health research data collection, analysis and reporting. Contribute to research that saves lives across Africa.', 'BSc Statistics, Actuarial Science, Bio-statistics, Public Health, Mathematics or related quantitative field. Proficiency in SPSS, Stata or R required.', '2025-10-01', '2025-11-30', 'Closed'),
(4,  4,  'Communications & Digital Media Intern - Nairobi City County seeks talented communications students to support media relations, digital content, public affairs and community engagement activities for Kenya''s capital city.', 'Diploma or Degree in Journalism, Mass Communication, Public Relations or Digital Media. Strong writing, photography and video editing skills required.', '2025-10-01', '2025-11-30', 'Closed'),
(5,  5,  'ICT Systems Developer Intern - KRA invites software engineering and IT students to work on the iTax platform and digital revenue mobilization tools. Contribute to Kenya''s tax modernization agenda.', 'BSc Computer Science, Information Technology, Software Engineering. Knowledge of PHP, Python, Java or .NET required. Minimum CGPA: 3.0.', '2025-10-01', '2025-11-30', 'Closed'),
(6,  6,  'Human Resources Management Intern - Equity Bank offers an immersive HR internship covering recruitment, performance management, learning & development, employee relations and HR analytics in a leading Pan-African bank.', 'Bachelor''s in Human Resource Management, Business Administration or Industrial/Organizational Psychology. Strong interpersonal and communication skills required.', '2025-10-01', '2025-11-30', 'Closed'),
(7,  18, 'Digital Innovation Intern - Ministry of ICT & Digital Economy - Work at the heart of Kenya''s digital transformation. Support policy development, digital inclusion programs and ICT sector regulation.', 'BSc Computer Science, Information Technology, Telecommunications or Policy Studies. Understanding of Kenya''s ICT regulatory framework is an advantage.', '2026-01-15', '2026-02-28', 'Active'),
(8,  19, 'Capital Markets & Securities Intern - NSE - Gain exposure to capital markets regulation, listings, trading operations and investor education at the Nairobi Securities Exchange, East Africa''s premier stock exchange.', 'BCom Finance, Economics, Actuarial Science or related quantitative field. CFA Level 1 candidate preferred. Strong analytical skills required.', '2026-01-15', '2026-02-28', 'Active'),
(9,  20, 'Audit & Assurance Intern - PwC Kenya - Join one of the Big Four professional services firms. Work on real audit engagements, financial advisory and risk assurance projects with blue-chip Kenyan and multinational clients.', 'BCom Accounting, Finance or equivalent. Minimum CGPA: 3.2. KASNEB Part 1 (CPA) completion preferred. Excellent analytical and communication skills.', '2026-01-15', '2026-02-28', 'Active'),
(10, 17, 'Research Assistant Intern - Strathmore University - Assist faculty researchers in data collection, analysis and academic publication preparation. Gain experience in academic research methodology across business, technology and social science domains.', 'Any year 3+ undergraduate degree with CGPA of 3.5 or higher. Strong research, writing and data analysis skills. Proficiency in at least one data analysis tool (SPSS, R, Python, Excel).', '2026-01-15', '2026-02-28', 'Active');

