SELECT '=== COMPREHENSIVE MOCK DATA VERIFICATION ===' AS Report;
SELECT 'Host Organizations' AS Entity, COUNT(*) AS Count FROM hostorganization;
SELECT 'Applications' AS Entity, COUNT(*) AS Total, SUM(ApplicationStatus='Approved') AS Approved, SUM(ApplicationStatus='Pending') AS Pending, SUM(ApplicationStatus='Rejected') AS Rejected FROM attachmentapplication;
SELECT 'Attachments' AS Entity, COUNT(*) AS Total, SUM(AttachmentStatus='Completed') AS Completed, SUM(AttachmentStatus='Ongoing') AS Ongoing FROM attachment WHERE AttachmentID <= 15;
SELECT 'Supervision Assignments' AS Entity, COUNT(*) AS Count FROM supervision WHERE AttachmentID <= 15;
SELECT 'Logbook Weeks' AS Entity, COUNT(*) AS Total, SUM(Status='Approved') AS Approved, SUM(Status='Pending') AS Pending FROM logbook WHERE AttachmentID <= 15;
SELECT 'Assessments' AS Entity, COUNT(*) AS Total, SUM(AssessmentType='First Assessment') AS First, SUM(AssessmentType='Final Assessment') AS Final FROM assessment WHERE AttachmentID <= 15;
SELECT 'Final Reports' AS Entity, COUNT(*) AS Total, SUM(Status='Approved') AS Approved, SUM(Status='Submitted') AS Submitted FROM finalreport WHERE AttachmentID <= 15;
SELECT 'Job Opportunities' AS Entity, COUNT(*) AS Count FROM attachmentopportunity;
SELECT 'Job Applications' AS Entity, COUNT(*) AS Total, SUM(Status='Accepted') AS Accepted, SUM(Status='Pending') AS Pending, SUM(Status='Rejected') AS Rejected FROM jobapplication;
